import 'dart:convert';

import 'package:crypto/crypto.dart';
import 'package:flutter/services.dart';

import '../../protocol/navivox_json.dart';

class DurableCredentialKeyAlias {
  const DurableCredentialKeyAlias.native(this.value);

  factory DurableCredentialKeyAlias.forGatewayInstall({
    required String gatewayId,
    required String appInstallIdentity,
  }) {
    final gateway = gatewayId.trim();
    final install = appInstallIdentity.trim();
    if (gateway.isEmpty || install.isEmpty) {
      throw ArgumentError(
        'Gateway identity and app install identity are required.',
      );
    }
    final digest = sha256.convert(utf8.encode('$gateway\u0000$install'));
    return DurableCredentialKeyAlias.native('navivox_durable_$digest');
  }

  final String value;

  @override
  String toString() => value;
}

class PublicJsonWebKey {
  const PublicJsonWebKey({
    required this.kty,
    required this.crv,
    required this.x,
    required this.y,
    required this.alg,
    this.kid,
  });

  factory PublicJsonWebKey.fromJson(Map<Object?, Object?> json) {
    return PublicJsonWebKey(
      kty: _requiredString(json, 'kty'),
      crv: _requiredString(json, 'crv'),
      x: _requiredString(json, 'x'),
      y: _requiredString(json, 'y'),
      alg: _requiredString(json, 'alg'),
      kid: _optionalString(json, 'kid'),
    );
  }

  final String kty;
  final String crv;
  final String x;
  final String y;
  final String alg;
  final String? kid;

  Map<String, Object?> toJson() => {
    'kty': kty,
    'crv': crv,
    'x': x,
    'y': y,
    'alg': alg,
    if (kid != null) 'kid': kid,
  };

  static String _requiredString(Map<Object?, Object?> json, String key) {
    final value = navivoxOptionalLiteralStringFromJson(json[key]);
    if (value == null) {
      throw FormatException('Missing public JWK field: $key');
    }
    return value;
  }

  static String? _optionalString(Map<Object?, Object?> json, String key) {
    return navivoxOptionalLiteralStringFromJson(json[key]);
  }
}

abstract interface class DurableCredentialKeyStore {
  Future<bool> isAvailable();

  Future<PublicJsonWebKey> createEs256KeyPair({
    required DurableCredentialKeyAlias alias,
  });

  Future<Uint8List> sign({
    required DurableCredentialKeyAlias alias,
    required Uint8List canonicalPayload,
  });

  Future<void> deleteKey({required DurableCredentialKeyAlias alias});
}

class GatewayCredentialMetadata {
  const GatewayCredentialMetadata({
    required this.gatewayId,
    required this.appInstallIdentity,
    required this.credentialLabel,
    required this.createdAt,
    this.lastUsedAt,
  });

  final String gatewayId;
  final String appInstallIdentity;
  final String credentialLabel;
  final DateTime createdAt;
  final DateTime? lastUsedAt;

  bool get isUsableMetadata {
    return gatewayId.trim().isNotEmpty &&
        appInstallIdentity.trim().isNotEmpty &&
        credentialLabel.trim().isNotEmpty;
  }
}

abstract interface class DurableCredentialStore {
  Future<bool> containsCredential({required String gatewayId});

  Future<GatewayCredentialMetadata?> metadata({required String gatewayId});

  Future<void> deleteCredential({required String gatewayId});
}

class EmptyDurableCredentialStore implements DurableCredentialStore {
  const EmptyDurableCredentialStore();

  @override
  Future<bool> containsCredential({required String gatewayId}) async => false;

  @override
  Future<GatewayCredentialMetadata?> metadata({
    required String gatewayId,
  }) async => null;

  @override
  Future<void> deleteCredential({required String gatewayId}) async {}
}

import 'package:shared_preferences/shared_preferences.dart';

import '../../protocol/navivox_json.dart';

/// Persists non-secret gateway metadata for later reconnect flows.
///
/// Pairing handoff tokens are bootstrap-only and must not be stored here.
/// Silent reconnect remains disabled until a secure durable credential adapter
/// exists for the saved Gateway identity.
class SessionPersistenceService {
  static const _keyBaseUrl = 'navivox.session.base_url';
  static const _keyWebSocketUrl = 'navivox.session.websocket_url';
  static const _legacyKeyToken = 'navivox.session.token';
  static const _keyLastConnectedAt = 'navivox.session.last_connected_at';
  static const _keyGatewayId = 'navivox.session.gateway_id';

  SharedPreferences? _prefs;

  Future<void> ensureInitialized() async {
    if (_prefs != null) return;
    try {
      _prefs = await SharedPreferences.getInstance();
    } catch (_) {
      // SharedPreferences not available (e.g. test without mock).
    }
  }

  /// Save non-secret gateway metadata after a successful gateway connection.
  Future<void> saveConnection({
    required String baseUrl,
    String? webSocketUrl,
    String? gatewayId,
  }) async {
    await ensureInitialized();
    final prefs = _prefs;
    if (prefs == null) return;
    await prefs.setString(_keyBaseUrl, baseUrl.trim());
    await prefs.remove(_legacyKeyToken);
    if (webSocketUrl != null && webSocketUrl.trim().isNotEmpty) {
      await prefs.setString(_keyWebSocketUrl, webSocketUrl.trim());
    }
    if (gatewayId != null && gatewayId.trim().isNotEmpty) {
      await prefs.setString(_keyGatewayId, gatewayId.trim());
    }
    await prefs.setString(
      _keyLastConnectedAt,
      DateTime.now().toUtc().toIso8601String(),
    );
  }

  /// Load saved connection state. Returns null if no session is saved.
  Future<SavedSession?> loadSession() async {
    await ensureInitialized();
    final prefs = _prefs;
    if (prefs == null) return null;
    final baseUrl = navivoxOptionalStringFromJson(prefs.getString(_keyBaseUrl));
    if (baseUrl == null) return null;

    return SavedSession(
      baseUrl: baseUrl,
      webSocketUrl: navivoxOptionalStringFromJson(
        prefs.getString(_keyWebSocketUrl),
      ),
      gatewayId: navivoxOptionalStringFromJson(prefs.getString(_keyGatewayId)),
      lastConnectedAt: navivoxDateTimeFromJson(
        prefs.getString(_keyLastConnectedAt),
      ),
    );
  }

  /// Remove saved session. Call when user explicitly disconnects,
  /// or when reconnect fails with an expired/revoked credential.
  Future<void> clearSession() async {
    await ensureInitialized();
    final prefs = _prefs;
    if (prefs == null) return;
    await prefs.remove(_keyBaseUrl);
    await prefs.remove(_legacyKeyToken);
    await prefs.remove(_keyWebSocketUrl);
    await prefs.remove(_keyLastConnectedAt);
    await prefs.remove(_keyGatewayId);
  }

  /// Check if a saved session exists without loading all fields.
  Future<bool> hasSession() async {
    await ensureInitialized();
    final prefs = _prefs;
    if (prefs == null) return false;
    final baseUrl = prefs.getString(_keyBaseUrl);
    return baseUrl != null && baseUrl.trim().isNotEmpty;
  }
}

class SavedSession {
  const SavedSession({
    required this.baseUrl,
    this.webSocketUrl,
    this.gatewayId,
    this.lastConnectedAt,
  });

  final String baseUrl;
  final String? webSocketUrl;
  final String? gatewayId;
  final DateTime? lastConnectedAt;

  /// Whether the session is stale (no recent connection).
  bool get isStale {
    if (lastConnectedAt == null) return true;
    return DateTime.now().toUtc().difference(lastConnectedAt!).inDays > 7;
  }

  /// Whether this metadata can currently perform silent reconnect.
  ///
  /// This remains false until a secure durable credential adapter exists.
  bool get canAttemptReconnect => false;
}

